using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
int t,tot;
int tr[(1<<10)+5][3];
bool ed[(1<<10)+5];
char s[105];
bool ins()
{
    int o=0,l=strlen(s),n;
    FOR(i,0,l-1)
    {
        if(ed[o])return 1;
        n=s[i]-'0';
        if(!tr[o][n])tr[o][n]=++tot;
        o=tr[o][n];
    }
    ed[o]=1;
    return (ed[tr[o][0]]||ed[tr[o][1]]);
}
signed main(void)
{
    t=0;
    wh(scanf("%s",s)!=EOF)
    {
        ++t;
        bool f=0;
        wh(s[0]!='9')
        {
            if(ins()) f=1;
            scanf("%s",s);
        }
        if(f)printf("Set %lld is not immediately decodable\n",t);
        else printf("Set %lld is immediately decodable\n",t);
        cl(tr);
		cl(ed);
		tot=1;
    }
    return false;
}
